SELECT 
FROM ability_goals g
LEFT JOIN ability_dimensions d ON g.dimension_id = d.id
LEFT JOIN users u ON g.student_id = u.id

    AND g.student_id = #{studentId}
    AND g.dimension_id = #{dimensionId}
    AND g.status = #{status}

ORDER BY g.created_at DESC
LIMIT #{offset}, #{size}

SELECT COUNT(1)
FROM ability_goals g

    AND g.student_id = #{studentId}
    AND g.dimension_id = #{dimensionId}
    AND g.status = #{status}
